import os

file_path = r"D:\ProgramData\deer-flow\backend\.deer-flow\threads\b81284f1-c55b-47bd-a4f9-88fb825c222c\user-data\uploads\第06章 按键输入与蜂鸣器-第三节-独立按键控制.md"

try:
    with open(file_path, 'rb') as f:
        # 读取前100个字节
        data = f.read(100)
        print("前100字节的十六进制表示:")
        hex_str = ' '.join(f'{b:02x}' for b in data)
        print(hex_str)

        print("\n对应的ASCII/字符表示:")
        # 尝试打印可打印字符
        for i, b in enumerate(data):
            if 32 <= b <= 126:  # 可打印ASCII
                print(f'{b:02x} ({chr(b)})', end=' ')
            else:
                print(f'{b:02x} (.)', end=' ')
            if (i + 1) % 16 == 0:
                print()

        # 检查常见的BOM
        bom_info = []
        if data[:3] == b'\xef\xbb\xbf':
            bom_info.append("UTF-8 BOM (EF BB BF)")
        if data[:2] == b'\xff\xfe':
            bom_info.append("UTF-16 LE BOM (FF FE)")
        if data[:2] == b'\xfe\xff':
            bom_info.append("UTF-16 BE BOM (FE FF)")

        if bom_info:
            print(f"\n检测到BOM: {', '.join(bom_info)}")
        else:
            print("\n未检测到BOM")

except Exception as e:
    print(f"错误: {e}")

