#!/usr/bin/env python3
# -*- coding: utf-8 -*-
import sys
import os
import json
from pathlib import Path

# 处理中文字符
import locale
locale.setlocale(locale.LC_ALL, 'en_US.UTF-8')

# 尝试导入python-pptx
try:
    from pptx import Presentation
    HAVE_PPTX = True
except ImportError:
    HAVE_PPTX = False
    print("警告：未安装python-pptx库")

def extract_ppt_content(ppt_path):
    """提取PPT文件的内容"""
    if not os.path.exists(ppt_path):
        return {"error": f"文件不存在: {ppt_path}", "slides": []}

    if not HAVE_PPTX:
        return {"error": "python-pptx库未安装", "slides": []}

    try:
        prs = Presentation(ppt_path)

        slides_info = []
        total_slides = len(prs.slides)

        print(f"PPT文件: {os.path.basename(ppt_path)}")
        print(f"总页数: {total_slides}")
        print("=" * 50)

        for i, slide in enumerate(prs.slides):
            slide_info = {
                "slide_number": i + 1,
                "layout": slide.slide_layout.name if slide.slide_layout else "未知",
                "shapes_count": len(slide.shapes),
                "text_content": []
            }

            # 提取文本内容
            for shape in slide.shapes:
                if hasattr(shape, "text"):
                    text = shape.text.strip()
                    if text:
                        slide_info["text_content"].append(text)
                # 检查表格
                elif shape.has_table:
                    table_text = []
                    for row in shape.table.rows:
                        row_text = []
                        for cell in row.cells:
                            if cell.text:
                                row_text.append(cell.text.strip())
                        if row_text:
                            table_text.append(" | ".join(row_text))
                    if table_text:
                        slide_info["text_content"].append("表格内容:\n" + "\n".join(table_text))

            slides_info.append(slide_info)

            # 打印每页摘要
            print(f"第 {i+1} 页 - 布局: {slide_info['layout']}, 形状数: {slide_info['shapes_count']}")
            if slide_info['text_content']:
                print("内容摘要:")
                for j, text in enumerate(slide_info['text_content'][:3]):  # 只显示前3个文本块
                    preview = text[:100] + "..." if len(text) > 100 else text
                    print(f"  {j+1}. {preview}")
                if len(slide_info['text_content']) > 3:
                    print(f"  还有 {len(slide_info['text_content']) - 3} 个文本块...")
            print("-" * 30)

        return {
            "filename": os.path.basename(ppt_path),
            "total_slides": total_slides,
            "slides": slides_info
        }

    except Exception as e:
        return {"error": f"解析PPT时出错: {str(e)}", "slides": []}

def main():
    ppt_path = "/mnt/user-data/uploads/第01章 第一二节 嵌入式系统概述及其硬件.pptx"

    if not HAVE_PPTX:
        print("尝试安装python-pptx库...")
        try:
            import subprocess
            subprocess.check_call([sys.executable, "-m", "pip", "install", "python-pptx"])
            from pptx import Presentation
            global HAVE_PPTX
            HAVE_PPTX = True
            print("python-pptx库安装成功")
        except Exception as e:
            print(f"安装python-pptx失败: {e}")
            print("\n作为备选方案，我可以：")
            print("1. 提取元数据信息")
            print("2. 尝试其他解析方法")

    result = extract_ppt_content(ppt_path)

    # 保存结果
    output_path = "/mnt/user-data/workspace/ppt_analysis.json"
    with open(output_path, 'w', encoding='utf-8') as f:
        json.dump(result, f, ensure_ascii=False, indent=2)

    print(f"\n分析结果已保存到: {output_path}")

    # 生成文本摘要
    if "error" not in result or not result["error"]:
        summary_path = "/mnt/user-data/workspace/ppt_summary.md"
        with open(summary_path, 'w', encoding='utf-8') as f:
            f.write(f"# PPT文件分析摘要\n\n")
            f.write(f"**文件名**: {result.get('filename', '未知')}\n")
            f.write(f"**总页数**: {result.get('total_slides', 0)}\n")
            f.write(f"**分析时间**: {os.path.basename(__file__)}\n\n")

            f.write("## 各页内容摘要\n\n")
            for slide in result.get("slides", []):
                f.write(f"### 第 {slide['slide_number']} 页\n")
                f.write(f"- **布局**: {slide['layout']}\n")
                f.write(f"- **形状数**: {slide['shapes_count']}\n")
                if slide['text_content']:
                    f.write(f"- **主要内容**:\n")
                    for text in slide['text_content']:
                        # 清理和简化文本
                        clean_text = text.replace('\n', ' ').replace('\r', '')
                        if len(clean_text) > 200:
                            clean_text = clean_text[:200] + "..."
                        f.write(f"  - {clean_text}\n")
                f.write("\n")

        print(f"文本摘要已保存到: {summary_path}")

    return result

if __name__ == "__main__":
    main()

