#!/usr/bin/env python3
import os
import struct

doc_path = "/mnt/user-data/uploads/《汇编语言》教案.doc"

if os.path.exists(doc_path):
    size = os.path.getsize(doc_path)
    print(f"文件大小: {size} bytes ({size/1024/1024:.1f} MB)")

    # 读取文件头判断类型
    with open(doc_path, 'rb') as f:
        header = f.read(20)
        print(f"文件头(16进制): {header.hex()}")

        # 检查是否是真正的doc格式
        if header[:8] == b'\xd0\xcf\x11\xe0\xa1\xb1\x1a\xe1':
            print("文件类型: OLE2 Compound Document (DOC/XLS/PPT)")
        elif header[:4] == b'PK\x03\x04':
            print("文件类型: ZIP (可能是DOCX/XLSX)")
        else:
            print("文件类型: 可能是旧版DOC或其他格式")

    # 尝试直接读取文本
    with open(doc_path, 'rb') as f:
        content = f.read()
        # 尝试解码其中的文本
        for encoding in ['gbk', 'gb2312', 'utf-8', 'utf-16', 'latin1']:
            try:
                text = content.decode(encoding, errors='ignore')
                # 查找中文字符
                chinese_chars = [c for c in text if '\u4e00' <= c <= '\u9fff']
                if len(chinese_chars) > 100:
                    print(f"\n=== 使用 {encoding} 解码成功，找到 {len(chinese_chars)} 个中文字符 ===")
                    # 提取有中文的部分
                    lines = text.split('\n')
                    for line in lines[:100]:
                        if any('\u4e00' <= c <= '\u9fff' for c in line):
                            print(line.strip())
                    break
            except:
                pass
else:
    print("文件不存在")

